  > 342:// `JSONSchema` represents properties from JSON Schema taken, and as used, in
  > 343:// the OpenAPI v2 spec.
  > 344://
  > 345:// This includes changes made by OpenAPI v2.
  > 346://
  > 347:// See: https://github.com/OAI/OpenAPI-Specification/blob/3.0.0/versions/2.0.md#schemaObject
  > 348://
  > 349:// See also: https://cswr.github.io/JsonSchema/spec/basic_types/,
  > 350:// https://github.com/json-schema-org/json-schema-spec/blob/master/schema.json
  > 351://
  > 352:// Example:
  > 353://
  > 354://  message SimpleMessage {
  > 355://    option (grpc.gateway.protoc_gen_openapiv2.options.openapiv2_schema) = {
  > 356://      json_schema: {
  > 357://        title: "SimpleMessage"
  > 358://        description: "A simple message."
  > 359://        required: ["id"]
  > 360://      }
  > 361://    };
  > 362://
  > 363://    // Id represents the message identifier.
  > 364://    string id = 1; [
  > 365://        (grpc.gateway.protoc_gen_openapiv2.options.openapiv2_field) = {
  > 366://          {description: "The unique identifier of the simple message."
  > 367://        }];
  > 368://  }
  > 369://
  > 370:message JSONSchema {
  > 371:	// field 1 is reserved for '$id', omitted from OpenAPI v2.
  > 372:	reserved 1;
  > 373:	// field 2 is reserved for '$schema', omitted from OpenAPI v2.
  > 374:	reserved 2;
  > 375:	// Ref is used to define an external reference to include in the message.
  > 376:	// This could be a fully qualified proto message reference, and that type must
  > 377:	// be imported into the protofile. If no message is identified, the Ref will
  > 378:	// be used verbatim in the output.
  > 379:	// For example:
  > 380:	//  `ref: ".google.protobuf.Timestamp"`.
  > 381:	string ref = 3;
  > 382:	// field 4 is reserved for '$comment', omitted from OpenAPI v2.
  > 383:	reserved 4;
  > 384:	// The title of the schema.
  > 385:	string title = 5;
  > 386:	// A short description of the schema.
  > 387:	string description = 6;
  > 388:	string default = 7;
  > 389:	bool read_only = 8;
  > 390:	// field 9 is reserved for 'examples', which is omitted from OpenAPI v2 in
  > 391:	// favor of 'example' field.
  > 392:	reserved 9;
  > 393:	double multiple_of = 10;
  > 394:	// Maximum represents an inclusive upper limit for a numeric instance. The
  > 395:	// value of MUST be a number,
  > 396:	double maximum = 11;
  > 397:	bool exclusive_maximum = 12;
  > 398:	// minimum represents an inclusive lower limit for a numeric instance. The
  > 399:	// value of MUST be a number,
  > 400:	double minimum = 13;
  > 401:	bool exclusive_minimum = 14;
  > 402:	uint64 max_length = 15;
  > 403:	uint64 min_length = 16;
  > 404:	string pattern = 17;
  > 405:	// field 18 is reserved for 'additionalItems', omitted from OpenAPI v2.
  > 406:	reserved 18;
  > 407:	// field 19 is reserved for 'items', but in OpenAPI-specific way.
  > 408:	// TODO(ivucica): add 'items'?
  > 409:	reserved 19;
  > 410:	uint64 max_items = 20;
  > 411:	uint64 min_items = 21;
  > 412:	bool unique_items = 22;
  > 413:	// field 23 is reserved for 'contains', omitted from OpenAPI v2.
  > 414:	reserved 23;
  > 415:	uint64 max_properties = 24;
  > 416:	uint64 min_properties = 25;
  > 417:	repeated string required = 26;
  > 418:	// field 27 is reserved for 'additionalProperties', but in OpenAPI-specific
  > 419:	// way. TODO(ivucica): add 'additionalProperties'?
  > 420:	reserved 27;
  > 421:	// field 28 is reserved for 'definitions', omitted from OpenAPI v2.
  > 422:	reserved 28;
  > 423:	// field 29 is reserved for 'properties', but in OpenAPI-specific way.
  > 424:	// TODO(ivucica): add 'additionalProperties'?
  > 425:	reserved 29;
  > 426:	// following fields are reserved, as the properties have been omitted from
  > 427:	// OpenAPI v2:
  > 428:	// patternProperties, dependencies, propertyNames, const
  > 429:	reserved 30 to 33;
  > 430:	// Items in 'array' must be unique.
  > 431:	repeated string array = 34;
  > 432:
  > 433:	enum JSONSchemaSimpleTypes {
  > 434:		UNKNOWN = 0;
  > 435:		ARRAY = 1;
  > 436:		BOOLEAN = 2;
  > 437:		INTEGER = 3;
  > 438:		NULL = 4;
  > 439:		NUMBER = 5;
  > 440:		OBJECT = 6;
  > 441:		STRING = 7;
  > 442:	}
  > 443:
  > 444:	repeated JSONSchemaSimpleTypes type = 35;
  > 445:	// following fields are reserved, as the properties have been omitted from
  > 446:	// OpenAPI v2: format, contentMediaType, contentEncoding, if, then, else
  > 447:	reserved 36 to 41;
  > 448:	// field 42 is reserved for 'allOf', but in OpenAPI-specific way.
  > 449:	// TODO(ivucica): add 'allOf'?
  > 450:	reserved 42;
  > 451:	// following fields are reserved, as the properties have been omitted from
  > 452:	// OpenAPI v2:
  > 453:	// anyOf, oneOf, not
  > 454:	reserved 43 to 45;
  > 455:}
