  > 478:// `SecurityDefinitions` is a representation of OpenAPI v2 specification's
  > 479:// Security Definitions object.
  > 480://
  > 481:// See: https://github.com/OAI/OpenAPI-Specification/blob/3.0.0/versions/2.0.md#securityDefinitionsObject
  > 482://
  > 483:// A declaration of the security schemes available to be used in the
  > 484:// specification. This does not enforce the security schemes on the operations
  > 485:// and only serves to provide the relevant details for each scheme.
  > 486:message SecurityDefinitions {
  > 487:	// A single security scheme definition, mapping a "name" to the scheme it
  > 488:	// defines.
  > 489:	map<string, SecurityScheme> security = 1;
  > 490:}
  > 491:
  > 492:// `SecurityScheme` is a representation of OpenAPI v2 specification's
  > 493:// Security Scheme object.
  > 494://
  > 495:// See: https://github.com/OAI/OpenAPI-Specification/blob/3.0.0/versions/2.0.md#securitySchemeObject
  > 496://
  > 497:// Allows the definition of a security scheme that can be used by the
  > 498:// operations. Supported schemes are basic authentication, an API key (either as
  > 499:// a header or as a query parameter) and OAuth2's common flows (implicit,
  > 500:// password, application and access code).
  > 501:message SecurityScheme {
  > 502:	// The type of the security scheme. Valid values are "basic",
  > 503:	// "apiKey" or "oauth2".
  > 504:	enum Type {
  > 505:		TYPE_INVALID = 0;
  > 506:		TYPE_BASIC = 1;
  > 507:		TYPE_API_KEY = 2;
  > 508:		TYPE_OAUTH2 = 3;
  > 509:	}
  > 510:
  > 511:	// The location of the API key. Valid values are "query" or "header".
  > 512:	enum In {
  > 513:		IN_INVALID = 0;
  > 514:		IN_QUERY = 1;
  > 515:		IN_HEADER = 2;
  > 516:	}
  > 517:
  > 518:	// The flow used by the OAuth2 security scheme. Valid values are
  > 519:	// "implicit", "password", "application" or "accessCode".
  > 520:	enum Flow {
  > 521:		FLOW_INVALID = 0;
  > 522:		FLOW_IMPLICIT = 1;
  > 523:		FLOW_PASSWORD = 2;
  > 524:		FLOW_APPLICATION = 3;
  > 525:		FLOW_ACCESS_CODE = 4;
  > 526:	}
  > 527:
  > 528:	// The type of the security scheme. Valid values are "basic",
  > 529:	// "apiKey" or "oauth2".
  > 530:	Type type = 1;
  > 531:	// A short description for security scheme.
  > 532:	string description = 2;
  > 533:	// The name of the header or query parameter to be used.
  > 534:	// Valid for apiKey.
  > 535:	string name = 3;
  > 536:	// The location of the API key. Valid values are "query" or
  > 537:	// "header".
  > 538:	// Valid for apiKey.
  > 539:	In in = 4;
  > 540:	// The flow used by the OAuth2 security scheme. Valid values are
  > 541:	// "implicit", "password", "application" or "accessCode".
  > 542:	// Valid for oauth2.
  > 543:	Flow flow = 5;
  > 544:	// The authorization URL to be used for this flow. This SHOULD be in
  > 545:	// the form of a URL.
  > 546:	// Valid for oauth2/implicit and oauth2/accessCode.
  > 547:	string authorization_url = 6;
  > 548:	// The token URL to be used for this flow. This SHOULD be in the
  > 549:	// form of a URL.
  > 550:	// Valid for oauth2/password, oauth2/application and oauth2/accessCode.
  > 551:	string token_url = 7;
  > 552:	// The available scopes for the OAuth2 security scheme.
  > 553:	// Valid for oauth2.
  > 554:	Scopes scopes = 8;
  > 555:	map<string, google.protobuf.Value> extensions = 9;
  > 556:}
