  > 571:	// scope names required for the execution. For other security scheme types,
  > 572:	// the array MUST be empty.
  > 573:	message SecurityRequirementValue {
  > 574:		repeated string scope = 1;
  > 575:	}
  > 576:	// Each name must correspond to a security scheme which is declared in
  > 577:	// the Security Definitions. If the security scheme is of type "oauth2",
  > 578:	// then the value is a list of scope names required for the execution.
  > 579:	// For other security scheme types, the array MUST be empty.
  > 580:	map<string, SecurityRequirementValue> security_requirement = 1;
  > 581:}
